  @fn renderCanvas(w, h)  @ 1040
  @fn pushBodyStyles()  @ 1313
  @fn popBodyStyles()  @ 1316
  -- Wiring scope
  @fn shortFxName(s)  @ 1382
      -- REAPER hands us "Type: Name (Author)" — or, for multi-out plugins,
